+		class ROBOTRACONTEUR_CORE_API async_signal_semaphore : private boost::noncopyable
+		{
+		protected:
+			boost::mutex this_lock;
+			boost::condition_variable next_wait;
+			boost::initialized<bool> running;
+			boost::initialized<bool> next;
+			boost::initialized<uint64_t> next_id;
+
+		public:
+			
+			template<typename F>
+			bool try_fire_next(BOOST_ASIO_MOVE_ARG(F) h)
+			{
+				boost::mutex::scoped_lock lock(this_lock);
+
+				if (running || next)
+				{
+					uint64_t my_id = ++next_id.data();
+
+					if (next.data())
+					{						
+						next_wait.notify_all();
+					}
+					else
+					{
+						next.data() = true;
+					}
+
+					while(running)
+					{
+						next_wait.wait(lock);
+						if (my_id != next_id)
+							return false;
+					} 
+
+					next.data() = false;					
+				}
+
+				running.data() = true;
+
+				BOOST_SCOPE_EXIT_TPL(this_)
+				{
+					boost::mutex::scoped_lock lock2(this_->this_lock);
+					this_->running.data() = false;
+					this_->next_wait.notify_all();
+				} BOOST_SCOPE_EXIT_END;
+
+				lock.unlock();
+
+				h();
+				
+				return true;
+			}
+		};
+
+		class ROBOTRACONTEUR_CORE_API async_signal_pool_semaphore : public RR_ENABLE_SHARED_FROM_THIS<async_signal_pool_semaphore>, private boost::noncopyable
+		{
+		protected:
+			boost::mutex this_lock;			
+			boost::initialized<bool> running;
+			boost::function<void()> next;
+			RR_WEAK_PTR<RobotRaconteurNode> node;
+
+		public:
+
+			async_signal_pool_semaphore(RR_SHARED_PTR<RobotRaconteurNode> node)
+			{
+				this->node = node;
+			}
+
+			template<typename F>
+			void try_fire_next(BOOST_ASIO_MOVE_ARG(F) h)
+			{
+				boost::mutex::scoped_lock lock(this_lock);
+
+				if (!running)
+				{
+					RR_SHARED_PTR<RobotRaconteurNode> node1 = this->node.lock();
+					if (!node1) return;
+					do_post(node1, h);
+				}
+				else
+				{
+					next = h;
+				}				
+			}
+
+		protected:
+
+			void do_fire_next(boost::function<void()>& h)
+			{
+				try
+				{
+					h();
+				}
+				catch (std::exception& exp)
+				{
+					handle_exception(&exp);
+				}
+
+				BOOST_SCOPE_EXIT(this_)
+				{
+					boost::mutex::scoped_lock lock2(this_->this_lock);
+					
+					boost::function<void()> h2;
+					h2.swap(this_->next);
+					this_->next.clear();
+					this_->running.data() = false;
+					if (!h2) return;
+					RR_SHARED_PTR<RobotRaconteurNode> node=this_->node.lock();
+					if (!node) return;
+					try
+					{
+						this_->do_post(node, boost::bind(&async_signal_pool_semaphore::do_fire_next, this_->shared_from_this(), h2));
+					}
+					catch (std::exception&) {}
+					this_->running.data() = true;
+
+				} BOOST_SCOPE_EXIT_END;
+			}
+
+			void do_post(RR_SHARED_PTR<RobotRaconteurNode> node1, RR_MOVE_ARG(boost::function<void()>) h);
+
+			void handle_exception(std::exception* exp);
+
+		};
+
+		void InvokeHandler_HandleException(RR_WEAK_PTR<RobotRaconteurNode> node, std::exception& exp);
+
+		void InvokeHandler_DoPost(RR_WEAK_PTR<RobotRaconteurNode> node, boost::function<void()>& h, bool shutdown_op = false, bool throw_on_released = true);
+
+		void InvokeHandler(RR_WEAK_PTR<RobotRaconteurNode> node, boost::function<void()>& handler);
+		
+		template<typename T>
+		void InvokeHandler(RR_WEAK_PTR<RobotRaconteurNode> node, typename boost::function<void(T)>& handler, T& value)
+		{
+			try
+			{
+				handler(value);
+			}
+			catch (std::exception& exp)
+			{
+				InvokeHandler_HandleException(node, exp);
+			}
+		}
+
+		void InvokeHandler(RR_WEAK_PTR<RobotRaconteurNode> node, boost::function<void(RR_SHARED_PTR<RobotRaconteurException>)>& handler);
+		
+		void InvokeHandlerWithException(RR_WEAK_PTR<RobotRaconteurNode> node, boost::function<void(RR_SHARED_PTR<RobotRaconteurException>)>& handler, RR_SHARED_PTR<RobotRaconteurException> exp);
+
+		void InvokeHandlerWithException(RR_WEAK_PTR<RobotRaconteurNode> node, boost::function<void(RR_SHARED_PTR<RobotRaconteurException>)>& handler, std::exception& exp, MessageErrorType default_err = MessageErrorType_UnknownError);
+		
+		template<typename T>
+		void InvokeHandler(RR_WEAK_PTR<RobotRaconteurNode> node, typename boost::function<void(T, RR_SHARED_PTR<RobotRaconteurException>)>& handler, T& value)
+		{
+			try
+			{
+				handler(value, RR_SHARED_PTR<RobotRaconteurException>());
+			}
+			catch (std::exception& exp)
+			{
+				InvokeHandler_HandleException(node, exp);
+			}
+		}
+
+		template<typename T>
+		void InvokeHandlerWithException(RR_WEAK_PTR<RobotRaconteurNode> node, typename boost::function<void(T, RR_SHARED_PTR<RobotRaconteurException>)>& handler, RR_SHARED_PTR<RobotRaconteurException> exp)
+		{
+			typename boost::initialized<T> default_value;
+			try
+			{
+				handler(default_value, exp);
+			}
+			catch (std::exception& exp)
+			{
+				InvokeHandler_HandleException(node, exp);
+			}
+		}
+
+		template<typename T>
+		void InvokeHandlerWithException(RR_WEAK_PTR<RobotRaconteurNode> node, typename boost::function<void(T, RR_SHARED_PTR<RobotRaconteurException>)>& handler, std::exception& exp, MessageErrorType default_err = MessageErrorType_UnknownError)
+		{
+			typename boost::initialized<boost::remove_const<boost::remove_reference<T>::type>::type> default_value;
+			try
+			{
+				RR_SHARED_PTR<RobotRaconteurException> err = RobotRaconteurExceptionUtil::ExceptionToSharedPtr(exp, default_err);
+				handler(default_value, err);
+			}
+			catch (std::exception& exp)
+			{
+				InvokeHandler_HandleException(node, exp);
+			}
+		}
+
+
+		void PostHandler(RR_WEAK_PTR<RobotRaconteurNode> node, boost::function<void()>& handler, bool shutdown_op = false, bool throw_on_released = true);
+		
+		template<typename T>
+		void PostHandler(RR_WEAK_PTR<RobotRaconteurNode> node, typename boost::function<void(T)>& handler, T& value, bool shutdown_op = false, bool throw_on_released = true)
+		{
+			boost::function<void()> h = boost::bind(handler, value);
+			InvokeHandler_DoPost(node, h, shutdown_op, throw_on_released);
+		}
+
+		void PostHandler(RR_WEAK_PTR<RobotRaconteurNode> node, boost::function<void(RR_SHARED_PTR<RobotRaconteurException>)>& handler, bool shutdown_op = false, bool throw_on_released = true);
+
+		void PostHandlerWithException(RR_WEAK_PTR<RobotRaconteurNode> node, boost::function<void(RR_SHARED_PTR<RobotRaconteurException>)>& handler, RR_SHARED_PTR<RobotRaconteurException> exp, bool shutdown_op = false, bool throw_on_released = true);
+
+		void PostHandlerWithException(RR_WEAK_PTR<RobotRaconteurNode> node, boost::function<void(RR_SHARED_PTR<RobotRaconteurException>)>& handler, std::exception& exp, MessageErrorType default_err = MessageErrorType_UnknownError, bool shutdown_op = false, bool throw_on_released = true);
+
+		template<typename T>
+		void PostHandler(RR_WEAK_PTR<RobotRaconteurNode> node, typename boost::function<void(T, RR_SHARED_PTR<RobotRaconteurException>)>& handler, T& value, bool shutdown_op = false, bool throw_on_released = true)
+		{
+			boost::function<void()> h=boost::bind(handler,value, RR_SHARED_PTR<RobotRaconteurException>());
+			InvokeHandler_DoPost(node, h, shutdown_op, throw_on_released);			
+		}
+
+		template<typename T>
+		void PostHandlerWithException(RR_WEAK_PTR<RobotRaconteurNode> node, typename boost::function<void(T, RR_SHARED_PTR<RobotRaconteurException>)>& handler, RR_SHARED_PTR<RobotRaconteurException> exp, bool shutdown_op = false, bool throw_on_released = true)
+		{
+			typename boost::initialized<T> default_value;
+			boost::function<void()> h = boost::bind(handler, default_value, RR_SHARED_PTR<RobotRaconteurException>());
+			InvokeHandler_DoPost(node, h, shutdown_op, throw_on_released);			
+		}
+
+		template<typename T>
+		void PostHandlerWithException(RR_WEAK_PTR<RobotRaconteurNode> node, typename boost::function<void(T, RR_SHARED_PTR<RobotRaconteurException>)>& handler, std::exception& exp, MessageErrorType default_err = MessageErrorType_UnknownError, bool shutdown_op = false, bool throw_on_released = true)
+		{
+			typename boost::initialized<T> default_value;
+			RR_SHARED_PTR<RobotRaconteurException> err = RobotRaconteurExceptionUtil::ExceptionToSharedPtr(exp, default_err);
+			boost::function<void()> h = boost::bind(handler, default_value, err);
+			InvokeHandler_DoPost(node, h, shutdown_op, throw_on_released);			
+		}
+
+	}
+}

