+			ar.push_back(RR_MAKE_SHARED<MessageElement>("real",arr->Real));
+			if (arr->Complex)
+			{
+				ar.push_back(RR_MAKE_SHARED<MessageElement>("imag",arr->Imag));
+			}
+
+			return RR_MAKE_SHARED<MessageElementMultiDimArray>(ar);
+		}
