+		U GetInValue(TimeSpec& ts, uint32_t& ep)
+		{
+			boost::mutex::scoped_lock lock(this_lock);
+			if (!in_value_valid) throw InvalidOperationException("Value not set");
+			ts = in_value_ts;
+			ep = in_value_ep;
