+void ASIOStreamBaseTransport::SimpleAsyncSendMessage(RR_SHARED_PTR<Message> m, boost::function<void(RR_SHARED_PTR<RobotRaconteurException>)>& callback)
+{
+	if (!connected.load()) return;
+	try
+	{
+		AsyncSendMessage(m, callback);
+	}
+	catch (std::exception&)
+	{
+		Close();
+	}
+
+}
