+{
+	RR_SHARED_PTR<MessageEntry> mm = RR_MAKE_SHARED<MessageEntry>(MessageEntryType_StreamOp, command);
+
+	if (command == "GetRemoteNodeID")
+	{
+	}
+	else
+	{
+			throw InvalidOperationException("Unknown StreamOp command");
+
+	}
+
+	return mm;
