+	bool AsyncMessageReaderImpl::read_uint_x(uint32_t& num)
+	{
+		
+		uint8_t b1;
+		if (!peek_byte(b1)) return false;
+		if (b1 <= 252)
+		{
+			read_number(b1);
+			num = b1;			
+			return true;
+		}
+		if (b1 == 253)
+		{
+			size_t a1 = available();
+			if (a1 < 3) return false;
+			read_number(b1);
+			uint16_t num2;
